# =============================================================================
# Permission Boundary
# Caps the maximum permissions any EC2 instance role can have.
# Even if the role policy is overly permissive, the boundary limits
# effective permissions to SSM, CloudWatch, and S3 log access only.
# Prevents instance credential abuse (MITRE T1552.005).
# =============================================================================
resource "aws_iam_policy" "ec2_permission_boundary" {
  name        = "netsec-ec2-permission-boundary"
  description = "Permission boundary for all EC2 instance roles"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid    = "AllowSSM"
        Effect = "Allow"
        Action = [
          "ssm:UpdateInstanceInformation",
          "ssmmessages:CreateControlChannel",
          "ssmmessages:CreateDataChannel",
          "ssmmessages:OpenControlChannel",
          "ssmmessages:OpenDataChannel",
          "ec2messages:AcknowledgeMessage",
          "ec2messages:DeleteMessage",
          "ec2messages:FailMessage",
          "ec2messages:GetEndpoint",
          "ec2messages:GetMessages",
          "ec2messages:SendReply"
        ]
        Resource = "*"
      },
      {
        Sid    = "AllowCloudWatchLogs"
        Effect = "Allow"
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents",
          "logs:DescribeLogStreams"
        ]
        Resource = "*"
      },
      {
        Sid    = "DenyIMDSv1"
        Effect = "Deny"
        Action = "ec2:ModifyInstanceMetadataOptions"
        Resource = "*"
        Condition = {
          StringEquals = {
            "ec2:MetadataHttpTokens" = "optional"
          }
        }
      }
    ]
  })

  tags = {
    Name = "netsec-ec2-permission-boundary"
  }
}

# =============================================================================
# IAM Role for SSM Session Manager (private EC2)
# Scoped with permission boundary to prevent credential abuse.
# =============================================================================
resource "aws_iam_role" "ssm_role" {
  name                 = "netsec-ssm-role"
  permissions_boundary = aws_iam_policy.ec2_permission_boundary.arn

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      }
    ]
  })

  tags = {
    Name = "netsec-ssm-role"
  }
}

resource "aws_iam_role_policy_attachment" "ssm_managed_policy" {
  role       = aws_iam_role.ssm_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonSSMManagedInstanceCore"
}

resource "aws_iam_instance_profile" "ssm_profile" {
  name = "netsec-ssm-instance-profile"
